 12→interface SearchBarProps {
 13→  value: string;
 14→  onChange: (value: string) => void;
 15→  placeholder?: string;
 16→  cyclingPlaceholders?: string[];
 17→  activeDescendantId?: string;
 18→  breadcrumbs?: BreadcrumbItem[];
 19→  dropdown?: ReactNode;
 20→}
 21→
 22→const CYCLE_INTERVAL = 4000;
 23→const FADE_DURATION = 300;
 24→
 25→function useCyclingPlaceholder(
 26→  placeholders: string[] | undefined,
 27→  isActive: boolean,
 28→): {
 29→  text: string | undefined;
 30→  visible: boolean;
 31→} {
 32→  const [index, setIndex] = useState(0);
 33→  const [visible, setVisible] = useState(true);
 34→
 35→  useEffect(() => {
 36→    if (!placeholders || placeholders.length <= 1 || !isActive) {
 37→      setIndex(0);
 38→      setVisible(true);
 39→      return;
 40→    }
 41→
 42→    let timeout: ReturnType<typeof setTimeout>;
 43→    const interval = setInterval(() => {
 44→      setVisible(false);
 45→      timeout = setTimeout(() => {
 46→        setIndex(prev => (prev + 1) % placeholders.length);
 47→        setVisible(true);
 48→      }, FADE_DURATION);
 49→    }, CYCLE_INTERVAL);
 50→
 51→    return () => {
 52→      clearInterval(interval);
 53→      clearTimeout(timeout);
 54→    };
 55→  }, [
 56→    placeholders,
 57→    isActive,
 58→  ]);
 59→
 60→  if (!placeholders || placeholders.length === 0) {
 61→    return {
 62→      text: undefined,
 63→      visible: true,
 64→    };
 65→  }
 66→
 67→  return {
 68→    text: placeholders[index % placeholders.length],
 69→    visible,
 70→  };
 71→}
 72→
 73→export function SearchBar({
 74→  value,
 75→  onChange,
 76→  placeholder = 'Search...',
 77→  cyclingPlaceholders,
 78→  activeDescendantId,
 79→  breadcrumbs,
 80→  dropdown,
 81→}: SearchBarProps) {
 82→  const inputRef = useRef<HTMLInputElement>(null);
 83→  const isEmpty = !value;
 84→  const cycling = useCyclingPlaceholder(cyclingPlaceholders, isEmpty);
 85→  const hasCycling =
 86→    cyclingPlaceholders && cyclingPlaceholders.length > 1 && isEmpty;
 87→
 88→  useEffect(() => {
 89→    inputRef.current?.focus();
 90→  }, []);
 91→
 92→  function handleInputKeyDown(e: KeyboardEvent<HTMLInputElement>) {
 93→    if (e.key !== 'Escape' || !breadcrumbs || breadcrumbs.length === 0) {
 94→      return;
 95→    }
 96→
 97→    e.preventDefault();
 98→    if (value) {
 99→      onChange('');
100→      return;
101→    }
102→
103→    for (let i = breadcrumbs.length - 1; i >= 0; i--) {
104→      const crumb = breadcrumbs[i];
105→      if (crumb?.onBack) {
106→        crumb.onBack();
107→        return;
108→      }
109→    }
110→  }
111→
112→  return (
113→    <div className="search-bar" role="search">
114→      <svg
115→        className="search-bar__icon"
116→        width="20"
117→        height="20"
118→        viewBox="0 0 20 20"
119→        fill="none"
120→        xmlns="http://www.w3.org/2000/svg"
121→      >
122→        <circle cx="9" cy="9" r="5.5" stroke="currentColor" strokeWidth="1.5" />
123→        <line
124→          x1="13.25"
125→          y1="13.25"
126→          x2="17.5"
127→          y2="17.5"
128→          stroke="currentColor"
129→          strokeWidth="1.5"
130→          strokeLinecap="round"
131→        />
132→      </svg>
133→      {breadcrumbs && breadcrumbs.length > 0 && (
134→        <nav className="search-bar__breadcrumbs" aria-label="Breadcrumb">
135→          {breadcrumbs.map((crumb, i) => {
136→            const isLast = i === breadcrumbs.length - 1;
137→            return (
138→              <Fragment key={i}>
139→                {i > 0 && (
140→                  <svg
141→                    className="search-bar__breadcrumb-chevron"
142→                    width="8"
143→                    height="8"
144→                    viewBox="0 0 8 8"
145→                    fill="none"
146→                    aria-hidden="true"
147→                  >
148→                    <path
149→                      d="M2.5 1.5L5.5 4L2.5 6.5"
150→                      stroke="currentColor"
151→                      strokeWidth="1.2"
152→                      strokeLinecap="round"
153→                      strokeLinejoin="round"
154→                    />
155→                  </svg>
156→                )}
157→                {isLast ? (
158→                  <span
159→                    className="search-bar__breadcrumb search-bar__breadcrumb--current"
160→                    aria-current="location"
161→                  >
162→                    {crumb.label}
163→                  </span>
164→                ) : (
165→                  <button
166→                    className="search-bar__breadcrumb"
167→                    onClick={crumb.onBack}
168→                    type="button"
169→                    aria-label={`Back to ${crumb.label}`}
170→                  >
171→                    {crumb.label}
172→                  </button>
173→                )}
174→              </Fragment>
175→            );
176→          })}
177→        </nav>
178→      )}
179→      <div className="search-bar__input-wrapper">
180→        <input
181→          ref={inputRef}
182→          className="search-bar__input"
183→          type="text"
184→          value={value}
185→          onChange={e => onChange(e.target.value)}
186→          onKeyDown={handleInputKeyDown}
187→          placeholder={hasCycling ? undefined : placeholder}
188→          role="combobox"
189→          aria-expanded={true}
190→          aria-controls="command-list"
191→          aria-activedescendant={activeDescendantId}
192→          aria-label="Search commands"
193→          spellCheck={false}
194→          autoComplete="off"
195→        />
196→        {hasCycling && (
197→          <span
198→            className={`search-bar__cycling-placeholder${cycling.visible ? '' : ' search-bar__cycling-placeholder--hidden'}`}
199→            aria-hidden="true"
200→          >
201→            {cycling.text}
202→          </span>
203→        )}
204→      </div>
205→      {dropdown}
206→    </div>
207→  );
208→}
