 107→export function RootSearchView({ onCompactChange }: RootSearchViewProps) {
 108→  const nav = useNavigation<NavViewData>();
 109→  const { push } = nav;
 110→
 111→  const [query, setQuery] = useState('');
 112→  const [filterValue, setFilterValue] = useState('all');
 113→  const [selectedIndex, setSelectedIndex] = useState(0);
 114→  const [actionsOpen, setActionsOpen] = useState(false);
 115→  const [quickLookOpen, setQuickLookOpen] = useState(false);
 116→
 117→  const { toasts, show: showToast, hide: hideToast } = useToast();
 118→  const { items: hudItems, show: showHUD } = useHUD();
 119→  const { alertState, confirmAlert, dismiss: dismissAlert } = useAlert();
 120→  const { favoriteIds, isFavorite, toggleFavorite, moveFavorite } =
 121→    useFavorites();
 122→  const { recentIds, addRecent } = useRecentCommands();
 123→  const { applications, refresh: refreshApps } = useApplications();
 124→
 125→  useEffect(() => {
 126→    if (nav.stackDepth === 0) {
 127→      setQuery('');
 128→      setFilterValue('all');
 129→      setSelectedIndex(0);
 130→      setActionsOpen(false);
 131→      setQuickLookOpen(false);
 132→    }
 133→  }, [nav.stackDepth]);
 134→
 135→  useEffect(() => {
 136→    if (!isTauri) return;
 137→    const platform = getPlatform();
 138→    let unsub: (() => void) | undefined;
 139→    let cancelled = false;
 140→
 141→    platform.window
 142→      .onFocusChanged(focused => {
 143→        if (focused) refreshApps();
 144→      })
 145→      .then(fn => {
 146→        if (cancelled) fn();
 147→        else unsub = fn;
 148→      });
 149→
 150→    return () => {
 151→      cancelled = true;
 152→      unsub?.();
 153→    };
 154→  }, [refreshApps]);
 155→
 156→  const appSection: SectionData | null = useMemo(() => {
 157→    if (applications.length === 0) return null;
 158→
 159→    const items: ListItemData[] = applications.map(app => ({
 160→      id: app.id,
 161→      title: app.name,
 162→      subtitle: 'Application',
 163→      icon: app.icon ? <AppIcon src={app.icon} /> : <AppPlaceholderIcon />,
 164→    }));
 165→
 166→    return {
 167→      title: 'Applications',
 168→      items,
 169→    };
 170→  }, [applications]);
 171→
 172→  const registrySections = useMemo(() => getSections(), []);
 173→
 174→  const allSections = useMemo(() => {
 175→    const sections = [...registrySections];
 176→    if (!appSection) return sections;
 177→
 178→    const existingIdx = sections.findIndex(s => s.title === 'Applications');
 179→    if (existingIdx >= 0) {
 180→      const existing = sections[existingIdx]!;
 181→      sections[existingIdx] = {
 182→        title: existing.title,
 183→        items: [
 184→          ...appSection.items,
 185→          ...existing.items,
 186→        ],
 187→      };
 188→    } else {
 189→      sections.push(appSection);
 190→    }
 191→    return sections;
 192→  }, [
 193→    registrySections,
 194→    appSection,
 195→  ]);
 196→
 197→  const filtered = useMemo(() => {
 198→    let sections = allSections;
 199→    if (filterValue === 'commands') {
 200→      sections = sections.filter(
 201→        s => s.title === 'Suggestions' || s.title === 'Commands',
 202→      );
 203→    } else if (filterValue === 'applications') {
 204→      sections = sections.filter(s => s.title === 'Applications');
 205→    }
 206→
 207→    let filteredResult: SectionData[];
 208→    if (query) {
 209→      const commandResults = searchCommands(query);
 210→      const appItems = appSection?.items ?? [];
 211→      const matchedApps = appItems
 212→        .map(item => ({
 213→          item,
 214→          score: fuzzyScore(query, item.title)?.score ?? -Infinity,
 215→        }))
 216→        .filter(({ score }) => score > -Infinity)
 217→        .sort((a, b) => b.score - a.score)
 218→        .map(({ item }) => item);
 219→
 220→      const mergedSections = [...commandResults];
 221→      if (matchedApps.length > 0) {
 222→        const appSectionIdx = mergedSections.findIndex(
 223→          s => s.title === 'Applications',
 224→        );
 225→        if (appSectionIdx >= 0) {
 226→          const existing = mergedSections[appSectionIdx]!;
 227→          const existingIds = new Set(existing.items.map(i => i.id));
 228→          const newApps = matchedApps.filter(a => !existingIds.has(a.id));
 229→          mergedSections[appSectionIdx] = {
 230→            title: existing.title,
 231→            items: [
 232→              ...newApps,
 233→              ...existing.items,
 234→            ],
 235→          };
 236→        } else {
 237→          mergedSections.push({
 238→            title: 'Applications',
 239→            items: matchedApps,
 240→          });
 241→        }
 242→      }
 243→
 244→      filteredResult = mergedSections
 245→        .map(s => {
 246→          if (filterValue === 'commands') {
 247→            return s.title === 'Suggestions' || s.title === 'Commands'
 248→              ? s
 249→              : {
 250→                  ...s,
 251→                  items: [],
 252→                };
 253→          }
 254→          if (filterValue === 'applications') {
 255→            return s.title === 'Applications'
 256→              ? s
 257→              : {
 258→                  ...s,
 259→                  items: [],
 260→                };
 261→          }
 262→          return s;
 263→        })
 264→        .filter(s => s.items.length > 0);
 265→    } else {
 266→      filteredResult = sections;
 267→    }
 268→
 269→    const allFlatItems = allSections.flatMap(s => s.items);
 270→    const favoriteItems = favoriteIds
 271→      .map(id => allFlatItems.find(item => item.id === id))
 272→      .filter((item): item is ListItemData => !!item);
 273→
 274→    if (query) {
 275→      const filteredFavs = favoriteItems.filter(
 276→        item =>
 277→          fuzzyMatch(query, item.title) ||
 278→          fuzzyMatch(query, item.subtitle ?? ''),
 279→      );
 280→      if (filteredFavs.length > 0) {
 281→        const favIds = new Set(filteredFavs.map(f => f.id));
 282→        const dedupedSections = filteredResult
 283→          .map(s => ({
 284→            ...s,
 285→            items: s.items.filter(item => !favIds.has(item.id)),
 286→          }))
 287→          .filter(s => s.items.length > 0);
 288→        return [
 289→          {
 290→            title: 'Favorites',
 291→            items: filteredFavs,
 292→          },
 293→          ...dedupedSections,
 294→        ];
 295→      }
 296→      return filteredResult;
 297→    }
 298→
 299→    const pinnedSections: SectionData[] = [];
 300→    const dedupIds = new Set<string>();
 301→
 302→    if (favoriteItems.length > 0) {
 303→      pinnedSections.push({
 304→        title: 'Favorites',
 305→        items: favoriteItems,
 306→      });
 307→      for (const item of favoriteItems) {
 308→        dedupIds.add(item.id);
 309→      }
 310→    }
 311→
 312→    const favSet = new Set(favoriteIds);
 313→    const recentItems = recentIds
 314→      .filter(id => !favSet.has(id))
 315→      .map(id => allFlatItems.find(item => item.id === id))
 316→      .filter((item): item is ListItemData => !!item);
 317→
 318→    if (recentItems.length > 0) {
 319→      pinnedSections.push({
 320→        title: 'Recent Commands',
 321→        items: recentItems,
 322→      });
 323→      for (const item of recentItems) {
 324→        dedupIds.add(item.id);
 325→      }
 326→    }
 327→
 328→    if (pinnedSections.length > 0) {
 329→      const dedupedSections = filteredResult
 330→        .map(s => ({
 331→          ...s,
 332→          items: s.items.filter(item => !dedupIds.has(item.id)),
 333→        }))
 334→        .filter(s => s.items.length > 0);
 335→      return [
 336→        ...pinnedSections,
 337→        ...dedupedSections,
 338→      ];
 339→    }
 340→
 341→    return filteredResult;
 342→  }, [
 343→    query,
 344→    filterValue,
 345→    favoriteIds,
 346→    recentIds,
 347→    allSections,
 348→    appSection,
 349→  ]);
 350→
 351→  const calculatorResult = useMemo(() => {
 352→    if (!query.trim()) return null;
 353→    return evaluate(query);
 354→  }, [query]);
 355→
 356→  const allItems = useMemo(() => {
 357→    const items = flattenItems(filtered);
 358→    if (calculatorResult) {
 359→      const calcItem: ListItemData = {
 360→        id: '__calculator__',
 361→        title: `= ${calculatorResult}`,
 362→        subtitle: query.trim(),
 363→        icon: <CalculatorIcon />,
 364→      };
 365→      return [
 366→        calcItem,
 367→        ...items,
 368→      ];
 369→    }
 370→    return items;
 371→  }, [
 372→    filtered,
 373→    calculatorResult,
 374→    query,
 375→  ]);
 376→
 377→  const appPathMap = useMemo(() => {
 378→    const map = new Map<string, string>();
 379→    for (const app of applications) {
 380→      map.set(app.id, app.path);
 381→    }
 382→    return map;
 383→  }, [applications]);
 384→
 385→  const selectedItem = allItems[selectedIndex];
 386→
 387→  const handleQueryChange = useCallback((value: string) => {
 388→    setQuery(value);
 389→    setSelectedIndex(0);
 390→    setActionsOpen(false);
 391→  }, []);
 392→
 393→  const handleFilterChange = useCallback((value: string) => {
 394→    setFilterValue(value);
 395→    setSelectedIndex(0);
 396→  }, []);
 397→
 398→  const handleActiveIndexChange = useCallback((index: number) => {
 399→    setSelectedIndex(index);
 400→    setActionsOpen(false);
 401→  }, []);
 402→
 403→  const handleDrillIn = useCallback(() => {
 404→    const item = allItems[selectedIndex];
 405→    if (!item) return;
 406→
 407→    setActionsOpen(false);
 408→
 409→    if (item.id === '__calculator__' && calculatorResult) {
 410→      performCopy(calculatorResult, showHUD, {
 411→        hudIcon: <ClipboardHUDIcon />,
 412→        hudTitle: `Copied ${calculatorResult}`,
 413→      });
 414→      return;
 415→    }
 416→
 417→    const appPath = appPathMap.get(item.id);
 418→    if (appPath) {
 419→      getPlatform()
